import re

def word_frequency(filepath: str) -> dict:
    """Count the frequency of each word in a text file."""
    with open(filepath, 'r', encoding='utf-8') as f:
        text = f.read().lower()

    words = re.findall(r'\b[a-z]+\b', text)
    return dict(Counter(words).most_common())

