import random

class ProducerConsumer:
    def __init__(self, buffer_size=10):
        self.buffer = queue.Queue(maxsize=buffer_size)
        self.lock = threading.Lock()
        self.running = True

    def producer(self, producer_id):
        while self.running:
            item = f"item-{producer_id}-{random.randint(1000, 9999)}"
            self.buffer.put(item)
            print(f"Producer {producer_id} produced: {item}")
            time.sleep(random.uniform(0.1, 0.5))

    def consumer(self, consumer_id):
        while self.running:
            try:
                item = self.buffer.get(timeout=1.0)
                print(f"Consumer {consumer_id} consumed: {item}")
                self.buffer.task_done()
            except queue.Empty:
                continue

    def start(self, num_producers=2, num_consumers=3):
        producers = [threading.Thread(target=self.producer, args=(i,)) for i in range(num_producers)]
        consumers = [threading.Thread(target=self.consumer, args=(i,), daemon=True) for i in range(num_consumers)]

        for t in producers + consumers:
            t.start()
        return producers, consumers

    def stop(self):
        self.running = False

