interface RequestConfig {
    headers?: Record<string, string>;
    params?: Record<string, string>;
    timeout?: number;
}

type Interceptor = (config: RequestInit & RequestConfig) => RequestInit & RequestConfig;

class ApiClient {
    private baseUrl: string;
    private interceptors: Interceptor[] = [];

    constructor(baseUrl: string) {
        this.baseUrl = baseUrl;
    }

    addInterceptor(interceptor: Interceptor): void {
        this.interceptors.push(interceptor);
    }

    private async request<T>(endpoint: string, config: RequestInit & RequestConfig = {}): Promise<T> {
        let finalConfig = { ...config };

        // Apply interceptors
        for (const interceptor of this.interceptors) {
            finalConfig = interceptor(finalConfig);
        }

        const url = new URL(endpoint, this.baseUrl);
        if (config.params) {
            Object.entries(config.params).forEach(([key, value]) => 
                url.searchParams.append(key, value)
            );
        }

        const response = await fetch(url.toString(), {
            ...finalConfig,
            headers: {
                'Content-Type': 'application/json',
                ...finalConfig.headers,
            },
        });

        if (!response.ok) {
            throw new Error(`API Error: ${response.status} ${response.statusText}`);
        }

        return response.json();
    }

    get<T>(endpoint: string, config?: RequestConfig): Promise<T> {
        return this.request<T>(endpoint, { ...config, method: 'GET' });
    }

    post<T>(endpoint: string, data: unknown, config?: RequestConfig): Promise<T> {
        return this.request<T>(endpoint, { ...config, method: 'POST', body: JSON.stringify(data) });
    }
}

