from typing import Any, Optional

class TTLCache:
    def __init__(self):
        self._store = {}
        self._lock = threading.Lock()

    def set(self, key: str, value: Any, ttl: Optional[float] = None) -> None:
        """Store a key-value pair with optional TTL in seconds."""
        expire_at = time.time() + ttl if ttl else None
        with self._lock:
            self._store[key] = (value, expire_at)

    def get(self, key: str) -> Optional[Any]:
        """Retrieve value by key, returning None if expired or missing."""
        with self._lock:
            if key not in self._store:
                return None
            value, expire_at = self._store[key]
            if expire_at and time.time() > expire_at:
                del self._store[key]
                return None
            return value

    def delete(self, key: str) -> bool:
        """Delete a key. Returns True if key existed."""
        with self._lock:
            return self._store.pop(key, None) is not None

    def cleanup(self) -> int:
        """Remove all expired keys. Returns count of removed keys."""
        now = time.time()
        expired = [k for k, (_, exp) in self._store.items() if exp and now > exp]
        with self._lock:
            for key in expired:
                self._store.pop(key, None)
        return len(expired)

    def size(self) -> int:
        """Return number of non-expired keys."""
        self.cleanup()
        return len(self._store)

