type Job struct {
	ID    int
	Data  string
}

type Result struct {
	JobID int
	Value string
	Err   error
}

func worker(ctx context.Context, id int, jobs <-chan Job, results chan<- Result, wg *sync.WaitGroup) {
	defer wg.Done()
	for {
		select {
		case job, ok := <-jobs:
			if !ok {
				return
			}
			// Simulate work
			time.Sleep(100 * time.Millisecond)
			results <- Result{
				JobID: job.ID,
				Value: fmt.Sprintf("processed by worker %d: %s", id, job.Data),
			}
		case <-ctx.Done():
			fmt.Printf("Worker %d shutting down\n", id)
			return
		}
	}
}

func main() {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	numWorkers := 3
	numJobs := 10
	jobs := make(chan Job, numJobs)
	results := make(chan Result, numJobs)
	var wg sync.WaitGroup

	// Start workers
	for i := 1; i <= numWorkers; i++ {
		wg.Add(1)
		go worker(ctx, i, jobs, results, &wg)
	}

	// Send jobs
	for j := 1; j <= numJobs; j++ {
		jobs <- Job{ID: j, Data: fmt.Sprintf("task-%d", j)}
	}
	close(jobs)

	// Wait and collect
	wg.Wait()
	close(results)

	for r := range results {
		fmt.Printf("Job %d: %s\n", r.JobID, r.Value)
	}
}

