import mmh3
import math
from bitarray import bitarray

class BloomFilter:
    def __init__(self, expected_items: int, false_positive_rate: float = 0.01):
        """Initialize a Bloom filter with optimal parameters."""
        self.size = self._optimal_size(expected_items, false_positive_rate)
        self.num_hashes = self._optimal_hashes(self.size, expected_items)
        self.bit_array = bitarray(self.size)
        self.bit_array.setall(0)
        self.count = 0

    @staticmethod
    def _optimal_size(n: int, p: float) -> int:
        return int(-n * math.log(p) / (math.log(2) ** 2))

    @staticmethod
    def _optimal_hashes(m: int, n: int) -> int:
        return int((m / n) * math.log(2))

    def add(self, item: str) -> None:
        """Add an item to the Bloom filter."""
        for seed in range(self.num_hashes):
            index = mmh3.hash(str(item), seed) % self.size
            self.bit_array[index] = 1
        self.count += 1

    def contains(self, item: str) -> bool:
        """Check if an item might be in the set. False = definitely not present."""
        for seed in range(self.num_hashes):
            index = mmh3.hash(str(item), seed) % self.size
            if not self.bit_array[index]:
                return False
        return True

    @property
    def false_positive_rate(self) -> float:
        """Current estimated false positive rate."""
        return (1 - math.exp(-self.num_hashes * self.count / self.size)) ** self.num_hashes

type EventMap = Record<string, unknown>;

type EventKey<T extends EventMap> = string & keyof T;
type EventCallback<T> = (payload: T) => void;

export class TypedEventEmitter<Events extends EventMap> {
    private listeners = new Map<string, Set<EventCallback<unknown>>>();

    on<K extends EventKey<Events>>(event: K, callback: EventCallback<Events[K]>): () => void {
        if (!this.listeners.has(event)) {
            this.listeners.set(event, new Set());
        }
        this.listeners.get(event)!.add(callback as EventCallback<unknown>);

        // Return unsubscribe function
        return () => this.off(event, callback);
    }

    off<K extends EventKey<Events>>(event: K, callback: EventCallback<Events[K]>): void {
        this.listeners.get(event)?.delete(callback as EventCallback<unknown>);
    }

    emit<K extends EventKey<Events>>(event: K, payload: Events[K]): void {
        const callbacks = this.listeners.get(event);
        if (callbacks) {
            for (const cb of callbacks) {
                try {
                    cb(payload);
                } catch (error) {
                    console.error(`Error in event handler for '${event}':`, error);
                }
            }
        }
    }

    once<K extends EventKey<Events>>(event: K, callback: EventCallback<Events[K]>): () => void {
        const wrapper: EventCallback<Events[K]> = (payload) => {
            this.off(event, wrapper);
            callback(payload);
        };
        return this.on(event, wrapper);
    }

    removeAllListeners(event?: string): void {
        if (event) {
            this.listeners.delete(event);
        } else {
            this.listeners.clear();
        }
    }
}

