sealed class ApiResult<out T> {
    data class Success<T>(val data: T) : ApiResult<T>()
    data class Error(val code: Int, val message: String, val details: String? = null) : ApiResult<Nothing>()
    data class NetworkError(val exception: Throwable) : ApiResult<Nothing>()
    object Loading : ApiResult<Nothing>()
}

class UserRepository(private val api: UserApi) {

    suspend fun getUser(id: String): ApiResult<User> = try {
        val response = api.getUser(id)
        if (response.isSuccessful) {
            ApiResult.Success(response.body()!!)
        } else {
            ApiResult.Error(
                code = response.code(),
                message = response.message(),
                details = response.errorBody()?.string()
            )
        }
    } catch (e: java.net.UnknownHostException) {
        ApiResult.NetworkError(e)
    } catch (e: java.net.SocketTimeoutException) {
        ApiResult.NetworkError(e)
    } catch (e: Exception) {
        ApiResult.Error(code = 0, message = "Unexpected error", details = e.message)
    }
}

